import React from "react";
import {
  PieChart,
  Pie,
  Cell,
  ResponsiveContainer,
  Tooltip,
  Legend,
} from "recharts";

export default function CategoryChart({ data, COLORS }) {
  return (
    <div className="w-full h-[260px] overflow-hidden">
      <ResponsiveContainer>
        <PieChart>
          <Pie
            data={data}
            dataKey="value"
            nameKey="category"
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={90}
            paddingAngle={3}
          >
            {data.map((entry, index) => (
              <Cell key={index} fill={COLORS[index % COLORS.length]} />
            ))}
          </Pie>

          <Tooltip />

          <Legend
            verticalAlign="bottom"
            height={36}
            wrapperStyle={{
              fontSize: "12px",
              color: "#ccc",
              overflow: "hidden",
            }}
            formatter={(value) =>
              value.length > 10 ? value.slice(0, 10) + "..." : value
            }
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
}
